function td_ipr_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('td_ipr');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	// automatic publications_and_intellectual_activities_details if passed as filterer
	if(Request::val('filterer_publications_and_intellectual_activities_details')) {
		$_REQUEST['publications_and_intellectual_activities_details'] = Request::val('filterer_publications_and_intellectual_activities_details');
	}

	$data = [
		'title' => Request::val('title', ''),
		'ipr_ia' => Request::val('ipr_ia', ''),
		'event_type' => Request::val('event_type', ''),
		'technology_domain' => Request::val('technology_domain', ''),
		'collaborating_organization' => Request::val('collaborating_organization', ''),
		'event_venue_address' => Request::val('event_venue_address', ''),
		'state' => Request::val('state', ''),
		'district' => Request::val('district', ''),
		'start_date' => Request::dateComponents('start_date', ''),
		'end_date' => Request::dateComponents('end_date', ''),
		'total_number_of_participants' => Request::val('total_number_of_participants', ''),
		'women_participants' => Request::val('women_participants', ''),
		'st_participants' => Request::val('st_participants', ''),
		'sc_participants' => Request::val('sc_participants', ''),
		'outcomes' => br2nl(Request::val('outcomes', '')),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];


	// automatic publications_and_intellectual_activities_details if passed as filterer
	if(Request::val('filterer_publications_and_intellectual_activities_details')) {
		$data['publications_and_intellectual_activities_details'] = Request::val('filterer_publications_and_intellectual_activities_details');
	}
	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('td_ipr', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		td_ipr_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function td_ipr_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function td_ipr_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('td_ipr', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: td_ipr_before_delete
	if(function_exists('td_ipr_before_delete')) {
		$args = [];
		if(!td_ipr_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `td_ipr` WHERE `id`='{$selected_id}'", $eo);

	// hook: td_ipr_after_delete
	if(function_exists('td_ipr_after_delete')) {
		$args = [];
		td_ipr_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='td_ipr' AND `pkValue`='{$selected_id}'", $eo);
}

