	}


	update_calc_fields('td_ipr', $data['selectedID'], calculated_fields()['td_ipr']);

	// hook: td_ipr_after_update
	if(function_exists('td_ipr_after_update')) {
		if($row = getRecord('td_ipr', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!td_ipr_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('td_ipr', $selected_id);
}

